407 | function handleExecuteCommand(ws, data) {
408 |   const { command, shell = 'bash', cwd } = data;
409 |   
410 |   if (!command) {
411 |     ws.send(JSON.stringify({ 
412 |       type: 'command_result', 
413 |       success: false, 
414 |       error: 'No command provided' 
415 |     }));
416 |     return;
417 |   }
418 |   
419 |   console.log(`[Server] Executing: ${command}`);
420 |   
421 |   const isWindows = process.platform === 'win32';
422 |   let shellCmd, args;
423 |   
424 |   if (shell === 'powershell' || (shell === 'bash' && isWindows)) {
425 |     shellCmd = isWindows ? 'powershell' : '/bin/bash';
426 |     args = isWindows ? ['-Command', command] : ['-c', command];
427 |   } else {
428 |     shellCmd = isWindows ? 'cmd' : '/bin/sh';
429 |     args = isWindows ? ['/c', command] : ['-c', command];
430 |   }
431 |   
432 |   const child = spawn(shellCmd, args, {
433 |     cwd: cwd || process.cwd(),
434 |     timeout: 60000,
435 |     maxBuffer: 10 * 1024 * 1024
436 |   });
437 |   
438 |   let stdout = '';
439 |   let stderr = '';
440 |   
441 |   child.stdout.on('data', (chunk) => {
442 |     stdout += chunk.toString();
443 |     ws.send(JSON.stringify({
444 |       type: 'command_output',
445 |       stream: 'stdout',
446 |       data: chunk.toString()
447 |     }));
448 |   });
449 |   
450 |   child.stderr.on('data', (chunk) => {
451 |     stderr += chunk.toString();
452 |     ws.send(JSON.stringify({
453 |       type: 'command_output',
454 |       stream: 'stderr',
455 |       data: chunk.toString()
456 |     }));
457 |   });
458 |   
459 |   child.on('close', (code) => {
460 |     ws.send(JSON.stringify({
461 |       type: 'command_result',
462 |       success: code === 0,
463 |       exitCode: code,
464 |       stdout: stdout.slice(-100000),
465 |       stderr: stderr.slice(-50000)
466 |     }));
467 |   });
468 |   
469 |   child.on('error', (err) => {
470 |     ws.send(JSON.stringify({
471 |       type: 'command_result',
472 |       success: false,
473 |       error: err.message
474 |     }));
475 |   });
476 | }
